CREATE TABLE organization_requirement_control_test_result_to_task
(
	id serial,
	organization_control_test_result_id integer NOT NULL,
	task_id integer DEFAULT NULL,

	CONSTRAINT pk_organization_requirement_control_test_result_to_task PRIMARY KEY (id)
	, CONSTRAINT fk_organization_requirement_control_test_result_to_task_to_control_test FOREIGN KEY (organization_control_test_result_id) REFERENCES organization_requirement_control_test_results (id) MATCH SIMPLE ON UPDATE CASCADE ON DELETE CASCADE
	, CONSTRAINT fk_organization_requirement_control_test_result_to_task_to_task FOREIGN KEY (task_id) REFERENCES tasks (id) MATCH SIMPLE ON UPDATE CASCADE ON DELETE CASCADE
);
